// Unit 27. Gevorderde Gesprekken
// Discourse Markers, Hedging & Nuance

export default {n:27,lang:"nl",srcLang:"en",track:"v2",title:"Gevorderde Gesprekken",sub:"Discourse Markers, Hedging & Nuance",icon:"💬",level:"B2.2",color:"#7B5EE8",lessons:[
  {id:"v2u27l1",title:"Nuanceren",icon:"🔮",xp:20,board:true,steps:[
        {type:"intro",title:"Nuanceren",desc:"Dutch speakers love to soften their statements. 'Misschien', 'wellicht', 'eventueel', and 'mogelijkerwijs' all mean 'maybe/perhaps' but at different formality levels. Mastering these is key to sounding natural.",goals:["4 hedging words at different formality levels","misschien, wellicht, eventueel, mogelijkerwijs","Soften statements like a native speaker","Register awareness in hedging"]},
        {type:"teach",trg:"misschien",src:"maybe / perhaps",pos:"adv",gender:null,phonetic:"mis-SKEEN",note:"Most common hedging word.\nEveryday register.\n'Misschien wel' = maybe so (softer).\n'Misschien niet' = maybe not.",example:"A: Ga je mee naar de bioscoop?\nB: Misschien, ik moet eerst kijken of ik tijd heb.\nA: Het is misschien een goed idee om vroeg te gaan.\nB: Misschien heb je gelijk.\nA: Laat me weten wat je beslist!",exampleSrc:"A: Are you coming to the cinema?\nB: Maybe, I need to check if I have time first.\nA: It's maybe a good idea to go early.\nB: Maybe you're right.\nA: Let me know what you decide!",funFact:"Register note: neutral in tone, used in spoken and written Dutch. Formal near-synonym: 'wellicht.'"},
        {type:"teach",trg:"wellicht",src:"perhaps / possibly",pos:"adv",gender:null,phonetic:"wel-LIKHT",note:"More formal than 'misschien'.\nCommon in essays, news, business.\n'Wellicht' = well (indeed) + licht (light/easy).\nSounds educated and thoughtful.",example:"A: Wellicht moeten we het anders aanpakken.\nB: Wat stel je voor?\nA: Wellicht is het beter om eerst te overleggen.\nB: Wellicht heb je gelijk.\nA: Laten we er morgen over praten.",exampleSrc:"A: Perhaps we should approach it differently.\nB: What do you suggest?\nA: Perhaps it's better to consult first.\nB: Perhaps you're right.\nA: Let's talk about it tomorrow.",funFact:"Perhaps / possibly. Native Dutch. Cognate with English 'well-lit'; wel + licht. Formal."},
        {type:"teach",trg:"eventueel",src:"possibly / if necessary / optionally",pos:"adv",gender:null,phonetic:"ay-ven-tu-AYL",note:"FALSE FRIEND with English 'eventual'!\nDutch 'eventueel' = possibly/optionally.\nEnglish 'eventually' = uiteindelijk.\nVery common in Dutch: 'eventueel' = if needed.",example:"A: We kunnen eventueel morgen afspreken.\nB: Of eventueel overmorgen?\nA: Eventueel kunnen we ook videobellen.\nB: Dat is eventueel een optie.\nA: Laten we kijken wat het beste uitkomt.",exampleSrc:"A: We could possibly meet tomorrow.\nB: Or possibly the day after?\nA: We could also possibly video call.\nB: That's possibly an option.\nA: Let's see what works best.",funFact:"latin cousin of English 'eventual (FALSE FRIEND!)'."},
        {type:"teach",trg:"mogelijkerwijs",src:"possibly (formal)",pos:"adv",gender:null,phonetic:"moh-GUH-luk-ur-wice",note:"Very formal: academic/legal/news register.\n'Mogelijk' = possible.\n'Mogelijkerwijs' = in a possible manner.\n'De mogelijkheid' = the possibility.\nUse in essays, not in casual chat.",example:"A: Mogelijkerwijs wordt de wet aangepast.\nB: Wanneer verwacht men dat?\nA: Mogelijkerwijs volgend jaar.\nB: Dat is nog onzeker.\nA: Inderdaad, het is nog niet bevestigd.",exampleSrc:"A: Possibly the law will be amended.\nB: When is that expected?\nA: Possibly next year.\nB: That's still uncertain.\nA: Indeed, it hasn't been confirmed yet.",funFact:"Possibly (formal). From mogelijk (possible) + -erwijs (-ly). Written register."},
        {type:"tip",title:"🔮 Hedging: Formality Ladder",text:"From casual to formal:\n\nmisschien (casual, everyday)\nwellicht (business, educated)\neventueel (if needed, optionally)\nmogelijkerwijs (formal, academic)\n\nDanger zone:\n'Eventueel' is a FALSE FRIEND!\nDutch: eventueel = possibly, if needed\nEnglish: eventually = uiteindelijk\n\n'We kunnen eventueel later afspreken.'\n= We can possibly meet later.\nNOT: We will eventually meet later."},
        {type:"mc",q:"'Eventueel' in Dutch means:",opts:["Possibly / if needed","Eventually","Certainly","Never"],ans:"Possibly / if needed",hint:"FALSE FRIEND with English! Not 'eventually'."},
        {type:"fb",opts:["Wellicht","Doordat","Mits","Tenzij"],hint:"Very formal synonym of misschien",s:"_____ moeten we het plan aanpassen.",a:"Wellicht"},
        {type:"match",pairs:[{trg:"misschien",src:"maybe (casual)"},{trg:"wellicht",src:"perhaps (formal)"},{trg:"eventueel",src:"possibly / if needed"},{trg:"mogelijkerwijs",src:"possibly (very formal)"}]},
        {type:"mc",q:"Which hedging word is most formal?",opts:["misschien","mogelijkerwijs","eventueel","wellicht"],ans:"mogelijkerwijs",hint:"Used in academic papers and legal documents"},
        {type:"fb",opts:["eventueel","mogelijkerwijs","doordat","mits"],hint:"Dutch word that softens: if needed, we could...",s:"We kunnen _____ morgen afspreken, als dat beter uitkomt.",a:"eventueel"},
        {type:"mc",q:"'Wellicht heb je gelijk' sounds:",opts:["Very casual","Rude","Educated and thoughtful","Childish"],ans:"Educated and thoughtful",hint:"A business/___ way to say 'perhaps'"},
        {type:"fb",opts:["Mogelijkerwijs","Misschien","Mits","Tenzij"],hint:"A very formal alternative to 'misschien'",s:"_____ wordt de wet volgend jaar aangepast.",a:"Mogelijkerwijs"},
        {type:"drag_fill",hint:"Formal email: PERHAPS. Casual text: MAYBE.",s:"In een e-mail aan je baas: '{1} kunnen we de vergadering verplaatsen.' In een app aan een vriend: '{2} morgen?'",blanks:{"1":"Wellicht","2":"Misschien"},pool:["Wellicht","Misschien","Mogelijkerwijs","Eventueel"]},
        {type:"mc",q:"English 'eventually' translates to Dutch:",opts:["eventueel","mogelijkerwijs","wellicht","uiteindelijk"],ans:"uiteindelijk",hint:"False friend alert: this Dutch word does NOT mean 'eventually'"},
        {type:"mc",q:"'Mogelijkerwijs' is used in:",opts:["Academic writing","Text messages","Children's books","Casual chats"],ans:"Academic writing",hint:"The most formal hedging word"},
        {type:"fb",opts:["Eventueel","Mogelijkerwijs","Doordat","Mits"],hint:"If needed, optionally (not misschien)",s:"_____ kun je morgen langskomen, als je tijd hebt.",a:"Eventueel"},
        {type:"mc",q:"Which is the correct Dutch translation of 'eventually'?",opts:["Eventueel","Uiteindelijk","Wellicht","Mogelijkerwijs"],ans:"Uiteindelijk",hint:"False friend: the Dutch word means 'possibly'. The English lookalike means?"}
  ]},
  {id:"v2u27l2",title:"Gespreksmarkers",icon:"💡",xp:20,board:true,steps:[
        {type:"intro",title:"Gespreksmarkers",desc:"Discourse markers are the glue of natural conversation. 'Overigens', 'trouwens', and 'eigenlijk' let you change topics, add information, and correct yourself smoothly.",goals:["overigens (by the way, incidentally)","trouwens (by the way, anyway)","eigenlijk (actually, really)","Smooth topic changes and asides"]},
        {type:"teach",trg:"overigens",src:"by the way / incidentally",pos:"adv",gender:null,phonetic:"OH-vuh-rih-guns",note:"Formal 'by the way'.\nUsed to introduce a new but related topic.\nMore formal than 'trouwens'.\nCommon in business and writing.",example:"A: Het vergaderverslag is klaar.\nB: Mooi. Overigens, heb je het nieuwe beleid gelezen?\nA: Nog niet. Overigens wilde ik je iets vragen.\nB: Zeg het maar.\nA: Overigens, wanneer is de deadline?",exampleSrc:"A: The meeting report is ready.\nB: Good. Incidentally, have you read the new policy?\nA: Not yet. By the way, I wanted to ask you something.\nB: Go ahead.\nA: By the way, when is the deadline?",funFact:"By the way / incidentally. Compound: over (over) + ig + -ens. Topic-shift connector."},
        {type:"teach",trg:"trouwens",src:"by the way / anyway",pos:"adv",gender:null,phonetic:"TROW-uns",note:"Casual 'by the way'.\nMore informal than 'overigens'.\nCan start a completely new topic.\nVery common in everyday speech.",example:"A: Ik ga boodschappen doen. Trouwens, heb jij melk nodig?\nB: Ja! Trouwens, ik wilde je iets vertellen.\nA: Wat dan?\nB: Ik heb een nieuwe baan! Trouwens, ik begin maandag.\nA: Gefeliciteerd!",exampleSrc:"A: I'm going grocery shopping. By the way, do you need milk?\nB: Yes! By the way, I wanted to tell you something.\nA: What?\nB: I got a new job! By the way, I start Monday.\nA: Congratulations!",funFact:"By the way / anyway. Native Dutch. More casual than overigens. Conversational topic-shift."},
        {type:"teach",trg:"eigenlijk",src:"actually / really / to be honest",pos:"adv",gender:null,phonetic:"AY-gun-luk",note:"Multi-purpose discourse marker.\n'Eigenlijk' can soften, correct, or redirect.\n'Eigenlijk niet' = actually not.\n'Wat wil je eigenlijk?' = What do you REALLY want?\nOne of the most used Dutch words.",example:"A: Hoe gaat het?\nB: Eigenlijk niet zo goed.\nA: Wat is er aan de hand?\nB: Ik wilde eigenlijk iets anders doen met mijn leven.\nA: Dat begrijp ik. Wat wil je eigenlijk?",exampleSrc:"A: How are you?\nB: Actually, not so well.\nA: What's going on?\nB: I actually wanted to do something else with my life.\nA: I understand. What do you actually want?",funFact:"Actually / to be honest. From 'eigen' (own). Literally 'own-ly.' Revelation marker."},
        {type:"teach",trg:"inderdaad",src:"indeed / that's right",pos:"adv",gender:null,phonetic:"in-dur-DAHT",note:"Confirms what someone said.\n'Inderdaad' = in + der + daad (in the deed).\nStronger than 'ja' (yes).\nShows you agree with emphasis.",example:"A: Het weer is slecht vandaag.\nB: Inderdaad, het regent al de hele dag.\nA: En morgen wordt het niet beter?\nB: Inderdaad niet, helaas.\nA: Welkom in Nederland!",exampleSrc:"A: The weather is bad today.\nB: Indeed, it's been raining all day.\nA: And tomorrow won't be better?\nB: Indeed not, unfortunately.\nA: Welcome to the Netherlands!",funFact:"Indeed / that's right. Compound: in + der + daad (deed). Literally 'in the deed.' Agreement marker."},
        {type:"tip",title:"💡 Topic Management in Dutch",text:"How Dutch speakers manage conversation flow:\n\nNew topic: Overigens/Trouwens, ... (by the way...)\nCorrection: Eigenlijk... (actually...)\nConfirmation: Inderdaad (indeed)\nReturn to topic: Maar goed... (anyway...)\nClarification: Ik bedoel... (I mean...)\n\nFormality:\noverigens > trouwens (formal > casual)\n\nEigenlijk is special:\n- It softens bad news: 'Eigenlijk niet zo goed.'\n- It redirects: 'Maar eigenlijk wilde ik...'\n- It corrects: 'Eigenlijk is dat niet waar.'"},
        {type:"mc",q:"'Overigens' and 'trouwens' both mean 'by the way'. 'Overigens' is:",opts:["More formal","More casual","More rude","More funny"],ans:"More formal",hint:"Business/writing register for 'by the way'. Trouwens = casual."},
        {type:"fb",opts:["Eigenlijk","Overigens","Trouwens","Inderdaad"],hint:"Softener before delivering a negative answer",s:"Hoe gaat het? _____ niet zo goed.",a:"Eigenlijk"},
        {type:"match",pairs:[{trg:"overigens",src:"by the way (formal)"},{trg:"trouwens",src:"by the way (casual)"},{trg:"eigenlijk",src:"actually"},{trg:"inderdaad",src:"indeed"}]},
        {type:"mc",q:"'Inderdaad, daar heb je gelijk in.' This expresses:",opts:["Disagreement","Strong confirmation","A question","A new topic"],ans:"Strong confirmation",hint:"Indeed = I confirm what you said"},
        {type:"fb",opts:["Overigens","Doordat","Mits","Hoewel"],hint:"Formal interjection to add a side remark",s:"Het rapport is klaar. _____, heb je het nieuwe beleid gelezen?",a:"Overigens"},
        {type:"mc",q:"'Eigenlijk wilde ik iets anders.' 'Eigenlijk' here means:",opts:["Unfortunately","Maybe","To be honest / actually","Certainly"],ans:"To be honest / actually",hint:"A Dutch adverb that corrects or redirects a conversation"},
        {type:"fb",opts:["Trouwens","Eigenlijk","Mogelijkerwijs","Hoewel"],hint:"Casual interjection to add a side remark",s:"Ik ga naar de winkel. _____, heb jij nog iets nodig?",a:"Trouwens"},
        {type:"drag_fill",hint:"INDEED, all day! BY THE WAY (casual), I wanted to ask...",s:"A: Het regent hard. B: {1}, al de hele dag! A: {2}, ik wilde je iets vragen.",blanks:{"1":"Inderdaad","2":"Trouwens"},pool:["Inderdaad","Trouwens","Overigens","Eigenlijk"]},
        {type:"mc",q:"Which marker would you use in a formal email?",opts:["Trouwens","Inderdaad","Eigenlijk","Overigens"],ans:"Overigens",hint:"The most formal 'by the way'"},
        {type:"mc",q:"'Eigenlijk niet zo goed' is a way to:",opts:["Soften bad news","Brag","Ask a question","Change the topic"],ans:"Soften bad news",hint:"Actually not so well = ___ed negative"},
        {type:"fb",opts:["Trouwens","Doordat","Mits","Hoewel"],hint:"Casual interjection: adding new information",s:"Het rapport is af. _____, de deadline is pas volgende week.",a:"Trouwens"},
        {type:"mc",q:"'Inderdaad' is stronger than a simple 'ja' because:",opts:["It's longer","It confirms with emphasis","It's casual","It's negative"],ans:"It confirms with emphasis",hint:"Indeed = emphatic confirmation"}
  ]},
  {id:"v2u27l3",title:"Meningen Geven",icon:"🗣️",xp:20,board:true,steps:[
        {type:"intro",title:"Meningen Geven",desc:"Beyond 'ik vind': formal opinion expressions for essays, meetings, and debates. 'Naar mijn mening', 'wat mij betreft', and 'ik ben van mening dat' elevate your Dutch to an advanced level.",goals:["naar mijn mening (in my opinion)","wat mij betreft (as far as I'm concerned)","ik ben van mening dat (I am of the opinion that)","meines Erachtens (in my view, very formal)"]},
        {type:"teach",trg:"naar mijn mening",src:"in my opinion",pos:"intj",gender:null,phonetic:"nahr mine MAY-ning",note:"Formal opinion phrase.\nAlternatives: 'volgens mij' (casual),\n'naar mijn idee' (neutral).\n'De mening' = the opinion.",example:"A: Wat vind je van het klimaatbeleid?\nB: Naar mijn mening is het niet ambitieus genoeg.\nA: Waarom niet?\nB: Naar mijn mening moeten we sneller handelen.\nA: Daar kan ik me in vinden.",exampleSrc:"A: What do you think of climate policy?\nB: In my opinion, it's not ambitious enough.\nA: Why not?\nB: In my opinion, we need to act faster.\nA: I can agree with that.",funFact:"In my opinion. 'Naar' (according to) + 'mijn mening' (my opinion). Formal alternative to 'volgens mij.'"},
        {type:"teach",trg:"wat mij betreft",src:"as far as I'm concerned",pos:"intj",gender:null,phonetic:"vat may buh-TREFT",note:"Personal standpoint phrase.\n'Wat hem/haar betreft' = as far as he/she is concerned.\n'Wat betreft' alone = regarding/concerning.\nVery common in meetings and debates.",example:"A: Zullen we het plan aanpassen?\nB: Wat mij betreft wel.\nA: Wat mij betreft moeten we meer investeren.\nB: Wat mij betreft is dat de beste optie.\nA: Dan zijn we het eens!",exampleSrc:"A: Shall we adjust the plan?\nB: As far as I'm concerned, yes.\nA: As far as I'm concerned, we need to invest more.\nB: As far as I'm concerned, that's the best option.\nA: Then we agree!",funFact:"As far as I'm concerned. Literally 'what concerns me.' Formal opinion structure."},
        {type:"teach",trg:"ik ben van mening dat",src:"I am of the opinion that",pos:"verb",gender:null,phonetic:"ik ben van MAY-ning dat",note:"Very ___ opinion expression.\nUsed in essays, formal debates, letters.\n'Van mening zijn dat...' = to be of the opinion that...\nFollowed by a subordinate clause.",example:"A: Wat is jouw standpunt?\nB: Ik ben van mening dat we meer moeten doen.\nA: Kun je dat toelichten?\nB: Ik ben van mening dat het onderwijs prioriteit moet zijn.\nA: Dat is een duidelijk standpunt.",exampleSrc:"A: What is your position?\nB: I am of the opinion that we should do more.\nA: Can you elaborate?\nB: I am of the opinion that education should be a priority.\nA: That's a clear position.",funFact:"'I am of the opinion that.' Formal opinion opener. Literally 'I am of opinion that.' Triggers verb-final word order in the clause."},
        {type:"teach",trg:"mijns inziens",src:"in my view / in my judgment",pos:"intj",gender:null,phonetic:"mines IN-zeens",note:"Very formal: 'in my view'.\nArchaic genitive construction.\n'Inzien' = to see into/understand.\nUse in formal essays and debates only.",example:"A: Is dit de beste oplossing?\nB: Mijns inziens wel.\nA: Waarom?\nB: Mijns inziens is het de meest effectieve aanpak.\nA: Je argumenten zijn overtuigend.",exampleSrc:"A: Is this the best solution?\nB: In my view, yes.\nA: Why?\nB: In my view, it's the most effective approach.\nA: Your arguments are convincing.",funFact:"In my view / in my judgment. Archaic genitive mijns + inziens (of my judgment). Very formal."},
        {type:"tip",title:"🗣️ Opinion Expressions: Formality Scale",text:"From casual to very formal:\n\nIk vind dat... = I think that... (casual)\nVolgens mij... = According to me... (neutral)\nNaar mijn mening... = In my opinion... (formal)\nWat mij betreft... = As far as I'm concerned... (formal)\nIk ben van mening dat... = I am of the opinion that... (very formal)\nMijns inziens... = In my view... (literary/legal)\n\nFor NT2 essays, use:\n'Naar mijn mening' or 'ik ben van mening dat'\nThese show advanced register awareness."},
        {type:"mc",q:"Which opinion expression is most casual?",opts:["Ik vind dat","Ik ben van mening dat","Mijns inziens","Naar mijn mening"],ans:"Ik vind dat",hint:"Ik ___ = I think/find (everyday)"},
        {type:"fb",opts:["Naar","Van","Met","Door"],hint:"Which preposition starts the formal opinion phrase: ___ mijn mening?",s:"_____ mijn mening moeten we meer investeren in onderwijs.",a:"Naar"},
        {type:"match",pairs:[
          {trg:"ik vind dat",src:"I think (casual)"},
          {trg:"naar mijn mening",src:"in my opinion (formal)"},
          {trg:"wat mij betreft",src:"as far as I'm concerned"},
          {trg:"mijns inziens",src:"in my view (literary)"}
        ]},
        {type:"mc",q:"'Ik ben van mening dat het onderwijs prioriteit moet zijn.' This is:",opts:["Very casual","Very formal","Slang","Incorrect"],ans:"Very formal",hint:"'Ik ben van mening dat' = ___ essay/debate register"},
        {type:"fb",opts:["mij","ik","mijn","me"],hint:"Wat ___ betreft: personal standpoint phrase",s:"Wat _____ betreft moeten we sneller handelen.",a:"mij"},
        {type:"mc",q:"'Mijns inziens' contains an old grammatical form called:",opts:["A diminutive","A plural","A genitive","A conditional"],ans:"A genitive",hint:"An archaic ___ form of 'mijn' used in formal expressions"},
        {type:"fb",opts:["Mijns","Mijn","Mij","Me"],hint:"An archaic genitive + 'inziens' = in one's view",s:"_____ inziens is dit de beste oplossing.",a:"Mijns"},
        {type:"drag_fill",hint:"Formal: IN MY OPINION. Casual: I THINK.",s:"Email to minister: '{1} mening is meer investering nodig.' Text to friend: 'Ik {2} dat we moeten gaan.'",blanks:{"1":"Naar mijn","2":"vind"},pool:["Naar mijn","vind","Mijns","ben van"]},
        {type:"mc",q:"For an NT2 essay, the best opinion phrase is:",opts:["Ik vind dat","Eigenlijk","Misschien","Naar mijn mening"],ans:"Naar mijn mening",hint:"The most formal and appropriate option for essays"},
        {type:"mc",q:"'Volgens mij' compared to 'naar mijn mening' is:",opts:["More casual/neutral","More formal","Identical","Rude"],ans:"More casual/neutral",hint:"Volgens mij = ___. Which phrase is the formal version?"},
        {type:"fb",opts:["ben","heb","ga","wil"],hint:"First person singular of zijn",s:"Ik _____ van mening dat we meer moeten investeren.",a:"ben"},
        {type:"mc",q:"For a formal letter, which opinion phrase is best?",opts:["Ik vind","Naar mijn mening","Misschien","Eigenlijk"],ans:"Naar mijn mening",hint:"Formal letter = formal opinion expression"}
  ]},
  {id:"v2u27l4",title:"Eens & Oneens",icon:"🤝",xp:20,board:true,steps:[
        {type:"intro",title:"Eens & Oneens",desc:"Agreeing and disagreeing in Dutch: from casual to formal, from complete agreement to polite disagreement. Dutch directness meets advanced nuance.",goals:["daar heb je een punt (you have a point)","dat klopt deels (that's partly true)","ik betwijfel of (I doubt whether)","Nuanced agreement and disagreement"]},
        {type:"teach",trg:"daar heb je een punt",src:"you have a point there",pos:"intj",gender:null,phonetic:"dahr hep yuh un punt",note:"Partial agreement: you acknowledge the other's argument.\n'Een punt hebben' = to have a point.\nUseful when you agree with part of an argument.\nNeutral to slightly formal.",example:"A: Ik denk dat we meer moeten investeren.\nB: Daar heb je een punt.\nA: Het onderwijs verdient meer geld.\nB: Daar heb je absoluut een punt.\nA: Laten we een voorstel schrijven.",exampleSrc:"A: I think we should invest more.\nB: You have a point there.\nA: Education deserves more money.\nB: You absolutely have a point.\nA: Let's write a proposal.",funFact:"You have a point there. Fixed phrase. Same as English idiom."},
        {type:"teach",trg:"dat klopt deels",src:"that's partly true",pos:"intj",gender:null,phonetic:"dat klopt dayls",note:"Diplomatic partial agreement.\n'Deels' = partly.\n'Dat klopt' = that's correct.\n'Dat klopt niet helemaal' = that's not entirely correct.\nGentler than 'dat klopt niet' (that's wrong).",example:"A: Nederlandse scholen zijn de beste ter wereld.\nB: Dat klopt deels. Ze zijn goed, maar niet overal.\nA: Wat bedoel je?\nB: In sommige regio's zijn er problemen.\nA: Dat is waar.",exampleSrc:"A: Dutch schools are the best in the world.\nB: That's partly true. They're good, but not everywhere.\nA: What do you mean?\nB: In some regions there are problems.\nA: That's true.",funFact:"That's partly true. Kloppen = to be correct (also: to knock). Partial-agreement marker."},
        {type:"teach",trg:"ik betwijfel of",src:"I doubt whether",pos:"verb",gender:null,phonetic:"ik buh-TWAY-ful of",note:"Polite disagreement through doubt.\n'Betwijfelen' = to doubt.\n'Ik betwijfel of...' = I doubt whether...\nSofter than 'dat is niet waar' (that's not true).",example:"A: Dit plan gaat werken!\nB: Ik betwijfel of dat realistisch is.\nA: Waarom?\nB: Ik betwijfel of we genoeg budget hebben.\nA: Misschien moeten we het aanpassen.",exampleSrc:"A: This plan is going to work!\nB: I doubt whether that's realistic.\nA: Why?\nB: I doubt whether we have enough budget.\nA: Maybe we should adjust it.",funFact:"'I doubt whether.' From 'twijfelen' (to doubt) + 'be-' (intensifier). 'Of' (whether) introduces uncertainty. Formal academic hedging."},
        {type:"teach",trg:"ik ben het daar niet mee eens",src:"I don't agree with that",pos:"verb",gender:null,phonetic:"ik ben hut dahr neet may ayns",note:"Direct disagreement (but polite).\n'Het eens zijn met' = to agree with.\n'Het oneens zijn met' = to disagree with.\nPerfectly acceptable in Dutch culture.",example:"A: We moeten bezuinigen op onderwijs.\nB: Ik ben het daar niet mee eens.\nA: Waarom niet?\nB: Onderwijs is een investering, geen kostenpost.\nA: Daar heb je een punt.",exampleSrc:"A: We need to cut spending on education.\nB: I don't agree with that.\nA: Why not?\nB: Education is an investment, not a cost.\nA: You have a point.",funFact:"'I don't agree with that.' Complex negation: 'niet' + 'mee eens' (in agreement with). 'Daar mee' = with that. Dismantles the phrase carefully."},
        {type:"tip",title:"🤝 Agreement Scale in Dutch",text:"From full agreement to full disagreement:\n\nAbsoluut! / Helemaal mee eens! = Absolutely! / Fully agree!\nDaar heb je gelijk in. = You're right about that.\nDaar heb je een punt. = You have a point. (partial)\nDat klopt deels. = That's partly true. (balanced)\nIk betwijfel of... = I doubt whether... (polite doubt)\nIk ben het er niet mee eens. = I disagree. (direct)\nDat klopt niet. = That's incorrect. (blunt)\n\nDutch tip: being direct about disagreement is NORMAL.\nBut at an advanced level, you can choose your LEVEL of directness."},
        {type:"mc",q:"'Daar heb je een punt' expresses:",opts:["Partial agreement","Full agreement","Full disagreement","Confusion"],ans:"Partial agreement",hint:"You have A point = I agree with part of it"},
        {type:"fb",opts:["klopt","is","heeft","gaat"],hint:"Dat _____ deels: acknowledging partial truth",s:"Dat _____ deels. Sommige scholen zijn goed, andere niet.",a:"klopt"},
        {type:"match",pairs:[{trg:"daar heb je een punt",src:"you have a point"},{trg:"dat klopt deels",src:"that's partly true"},{trg:"ik betwijfel of",src:"I doubt whether"},{trg:"helemaal mee eens",src:"fully agree"}]},
        {type:"mc",q:"'Ik betwijfel of dat realistisch is' is:",opts:["Rude and confrontational","Polite disagreement through doubt","Full explicit agreement","A direct question"],ans:"Polite disagreement through doubt",hint:"A softer way to express ___ than saying 'that's wrong'"},
        {type:"fb",opts:["ben","heb","ga","wil"],hint:"Which form of zijn fits with 'ik' here?",s:"We moeten bezuinigen. Ik _____ het daar niet mee eens.",a:"ben"},
        {type:"mc",q:"On the agreement scale, 'dat klopt deels' is:",opts:["Stronger than 'absoluut' is","Full explicit disagreement","Between agreement and disagreement","A clarifying question (in most cases)"],ans:"Between agreement and disagreement",hint:"Partly = balanced/middle position"},
        {type:"fb",opts:["betwijfel","geloof","weet","vind"],hint:"Ik _____ of: expressing uncertainty",s:"Ik _____ of we genoeg budget hebben voor dit plan.",a:"betwijfel"},
        {type:"drag_fill",hint:"You HAVE a point, but I DOUBT whether more meetings help",s:"Collega: 'We moeten meer vergaderen.' Jij: '{1} heb je een punt, maar ik {2} of meer vergaderingen helpen.'",blanks:{"1":"Daar","2":"betwijfel"},pool:["Daar","betwijfel","Wellicht","vind"]},
        {type:"mc",q:"In Dutch culture, saying 'ik ben het er niet mee eens' is:",opts:["Very rude and direct","Too formal for everyday","Only for bosses in meetings","Normal and acceptable"],ans:"Normal and acceptable",hint:"Dutch directness: disagreeing openly is fine"},
        {type:"mc",q:"'Dat klopt niet helemaal' is:",opts:["A diplomatic partial disagreement","Very aggressive","Full agreement","A question"],ans:"A diplomatic partial disagreement",hint:"Not entirely correct = gentle ___"},
        {type:"fb",opts:["eens","samen","goed","klaar"],hint:"Het er niet mee _____ zijn",s:"Ik ben het er niet mee _____. Onderwijs verdient meer geld.",a:"eens"},
        {type:"mc",q:"Dutch directness means that saying 'ik ben het oneens' is:",opts:["Always rude","Normal and expected","Only for the boss","Against the rules"],ans:"Normal and expected",hint:"Direct disagreement is fine in Dutch culture"}
  ]},
  {id:"v2u27l5",title:"Om Eerlijk Te Zijn",icon:"💎",xp:20,board:true,steps:[
        {type:"intro",title:"Om Eerlijk Te Zijn",desc:"Conversation management phrases that help you steer discussions: 'om eerlijk te zijn' (to be honest), 'wat ik bedoel is' (what I mean is), and 'laat ik het zo zeggen' (let me put it this way).",goals:["om eerlijk te zijn (to be honest)","wat ik bedoel is (what I mean is)","laat ik het zo zeggen (let me put it this way)","Manage conversations smoothly"]},
        {type:"teach",trg:"om eerlijk te zijn",src:"to be honest",pos:"verb",gender:null,phonetic:"om AIR-luk tuh zine",note:"Introduces honest (sometimes negative) feedback.\n'Eerlijk' = honest.\n'Om eerlijk te zijn' signals candor.\nOften precedes criticism or bad news.",example:"A: Hoe vond je de presentatie?\nB: Om eerlijk te zijn, het was niet zo sterk.\nA: Wat kon beter?\nB: Om eerlijk te zijn, de structuur miste.\nA: Dank je voor je eerlijkheid.",exampleSrc:"A: How did you find the presentation?\nB: To be honest, it wasn't that strong.\nA: What could be better?\nB: To be honest, the structure was missing.\nA: Thank you for your honesty.",funFact:"'To be honest.' Infinitive of purpose: 'om' + 'te' + infinitive. 'Eerlijk' (honest) + 'zijn' (to be). Common conversational opener."},
        {type:"teach",trg:"wat ik bedoel is",src:"what I mean is",pos:"intj",gender:null,phonetic:"vat ik buh-DOOL is",note:"Clarification phrase.\n'Bedoelen' = to mean/intend.\n'Wat bedoel je?' = What do you mean?\nUseful when your first explanation wasn't clear.",example:"A: Ik begrijp je niet helemaal.\nB: Wat ik bedoel is dat we het anders moeten doen.\nA: Ah, nu snap ik het.\nB: Wat ik bedoel is dat kwaliteit belangrijker is dan snelheid.\nA: Dat is een goed punt.",exampleSrc:"A: I don't entirely understand you.\nB: What I mean is that we need to do it differently.\nA: Ah, now I get it.\nB: What I mean is that quality is more important than speed.\nA: That's a good point.",funFact:"What I mean is. Clarification structure. Bedoelen = to mean."},
        {type:"teach",trg:"laat ik het zo zeggen",src:"let me put it this way",pos:"intj",gender:null,phonetic:"laht ik hut zo ZEG-un",note:"Diplomatic rephrasing phrase.\nUsed to soften criticism or find a better wording.\n'Laten we zeggen dat...' = let's say that...\nSignals careful word choice.",example:"A: Vind je het een goed plan?\nB: Laat ik het zo zeggen: het kan beter.\nA: Wat bedoel je?\nB: Laat ik het zo zeggen: er zijn betere alternatieven.\nA: Kun je een voorbeeld geven?",exampleSrc:"A: Do you think it's a good plan?\nB: Let me put it this way: it could be better.\nA: What do you mean?\nB: Let me put it this way: there are better alternatives.\nA: Can you give an example?",funFact:"Let me put it this way. Imperative laten + zo (so/thus) + zeggen."},
        {type:"teach",trg:"maar goed",src:"anyway / but well / moving on",pos:"intj",gender:null,phonetic:"mahr goot",note:"Topic-closing/redirecting phrase.\n'Maar goed' = but well/anyway.\nUsed to move past a topic.\n'Maar goed, dat is nu voorbij' = anyway, that's over now.",example:"A: Het was een lastige vergadering.\nB: Maar goed, we hebben een besluit genomen.\nA: Inderdaad. Maar goed, wat is de volgende stap?\nB: Maar goed, laten we vooruit kijken.\nA: Goed idee.",exampleSrc:"A: It was a tough meeting.\nB: Anyway, we made a decision.\nA: Indeed. Anyway, what's the next step?\nB: Anyway, let's look forward.\nA: Good idea.",funFact:"Anyway / but well / moving on. Casual topic-shift, similar to English 'anyway.' Conversational."},
        {type:"tip",title:"💎 Conversation Steering in Dutch",text:"How to manage Dutch conversations:\n\nIntroduce honest feedback:\nom eerlijk te zijn... (to be honest...)\n\nClarify yourself:\nwat ik bedoel is... (what I mean is...)\nik bedoel... (I mean...)\n\nSoften/rephrase:\nlaat ik het zo zeggen... (let me put it this way...)\n\nChange topic:\nmaar goed... (anyway...)\nhoe dan ook... (in any case...)\n\nReturn to topic:\nwaar was ik gebleven? (where was I?)\nterug naar het onderwerp... (back to the topic...)"},
        {type:"mc",q:"'Om eerlijk te zijn' usually precedes:",opts:["Honest feedback, often critical","A generous and warm compliment","A lighthearted and funny joke","A polite and indirect question"],ans:"Honest feedback, often critical",hint:"To be ___... (signals candor)"},
        {type:"fb",opts:["bedoel","vind","weet","zie"],hint:"Wat ik _____: clarifying your intention",s:"Ik begrijp je niet. Wat ik _____ is dat we het anders moeten doen.",a:"bedoel"},
        {type:"match",pairs:[{trg:"om eerlijk te zijn",src:"to be honest"},{trg:"wat ik bedoel is",src:"what I mean is"},{trg:"laat ik het zo zeggen",src:"let me put it this way"},{trg:"maar goed",src:"anyway / moving on"}]},
        {type:"mc",q:"'Laat ik het zo zeggen: het kan beter.' The speaker is being:",opts:["Very direct and rude","Diplomatically critical","Enthusiastically positive","Confused"],ans:"Diplomatically critical",hint:"Let me put it this way = choosing words carefully"},
        {type:"fb",opts:["Maar","Om","Wat","Laat"],hint:"Goed, moving on from the current topic",s:"Het was een moeilijke dag. _____ goed, morgen is er weer een nieuwe dag.",a:"Maar"},
        {type:"mc",q:"'Wat ik bedoel is' is used when:",opts:["You want to change the subject","You want to end the conversation","Your first explanation wasn't clear enough","You're angry (in most cases) (in most cases)"],ans:"Your first explanation wasn't clear enough",hint:"Clarification: this is what I ACTUALLY mean"},
        {type:"fb",opts:["Om","Na","Bij","In"],hint:"___ eerlijk te zijn: introducing honesty",s:"_____ eerlijk te zijn, de presentatie was niet sterk genoeg.",a:"Om"},
        {type:"drag_fill",hint:"LET me put it this way... TO be honest...",s:"A: Vind je het plan goed? B: {1} ik het zo zeggen: het heeft potentieel. A: {2} eerlijk te zijn, ik twijfel ook.",blanks:{"1":"Laat","2":"Om"},pool:["Laat","Om","Wat","Maar"]},
        {type:"mc",q:"'Maar goed' is used to:",opts:["Express strong agreement","Ask a question","Start an argument","Move past a topic"],ans:"Move past a topic",hint:"Anyway... let's ___ on"},
        {type:"mc",q:"'Om eerlijk te zijn' often comes BEFORE:",opts:["Critical feedback","A compliment","A joke","A greeting"],ans:"Critical feedback",hint:"To be honest = signals honesty, often before criticism"},
        {type:"fb",opts:["gebleven","gegaan","gekomen","geweest"],hint:"Where was I? (returning to a topic)",s:"Waar was ik _____? Oh ja, ik had het over het nieuwe plan.",a:"gebleven"},
        {type:"mc",q:"'Hoe dan ook' at the start of a sentence means:",opts:["How is that possible","In any case / regardless","How did that happen","What do you think"],ans:"In any case / regardless",hint:"A discourse marker that dismisses previous complications"}
  ]},
  {id:"v2u27l6",title:"Tenslotte & Kortom",icon:"📋",xp:20,board:true,steps:[
        {type:"intro",title:"Tenslotte & Kortom",desc:"Summarizing and confirming markers to wrap up conversations and arguments. 'Tenslotte' (after all), 'kortom' (in short), and 'al met al' (all in all) help you draw conclusions.",goals:["tenslotte (after all)","al met al (all in all)","hoe dan ook (in any case)","Wrap up conversations and arguments"]},
        {type:"teach",trg:"tenslotte",src:"after all",pos:"adv",gender:null,phonetic:"ten-SLOT-uh",note:"NOTE: 'tenslotte' (one word) = after all.\n'Ten slotte' (two words) = finally/lastly.\nDifferent meanings! Common mistake.\n'Tenslotte' justifies an action or statement.",example:"A: Waarom help je hem?\nB: Hij is tenslotte mijn broer.\nA: Dat is waar.\nB: Tenslotte helpt familie elkaar.\nA: Tenslotte is dat het belangrijkste.",exampleSrc:"A: Why are you helping him?\nB: After all, he's my brother.\nA: That's true.\nB: After all, family helps each other.\nA: After all, that's the most important thing.",funFact:"After all. Also: finally. Dual-use connector. Context decides meaning."},
        {type:"teach",trg:"al met al",src:"all in all / all things considered",pos:"intj",gender:null,phonetic:"al met al",note:"Balanced summary phrase.\n'Al met al' = taking everything together.\nUsed after listing positives and negatives.\nNeutral register, works everywhere.",example:"A: Hoe was je vakantie?\nB: Al met al was het een goede reis.\nA: Ondanks het slechte weer?\nB: Al met al viel het mee.\nA: Al met al heb je genoten?",exampleSrc:"A: How was your vacation?\nB: All in all, it was a good trip.\nA: Despite the bad weather?\nB: All in all, it wasn't that bad.\nA: All in all, you enjoyed it?",funFact:"All in all / all things considered. Reduplicated al (all). Summary formula."},
        {type:"teach",trg:"hoe dan ook",src:"in any case / no matter what",pos:"intj",gender:null,phonetic:"hoo dan oak",note:"'Hoe dan ook' = however it may be.\nDismisses uncertainty, moves forward.\n'Hoe het ook zij' = however it may be (formal).\nUseful for decisive conclusions.",example:"A: Het plan werkt misschien niet.\nB: Hoe dan ook, we moeten iets doen.\nA: Hoe dan ook, stilzitten is geen optie.\nB: Daar ben ik het mee eens.\nA: Hoe dan ook, laten we beginnen.",exampleSrc:"A: The plan might not work.\nB: In any case, we need to do something.\nA: In any case, sitting still is not an option.\nB: I agree.\nA: In any case, let's begin.",funFact:"In any case / no matter what. Fixed phrase. Three-word dismissive of specifics."},
        {type:"teach",trg:"per saldo",src:"on balance / when all is said and done",pos:"intj",gender:null,phonetic:"per SAL-do",note:"Financial metaphor: net balance.\n'Saldo' = balance (banking term).\n'Per saldo' = when you weigh everything up.\nFormal/business register.",example:"A: Er waren voor- en nadelen.\nB: Per saldo was het een succes.\nA: Ondanks de problemen?\nB: Per saldo hebben we meer bereikt dan verloren.\nA: Dat is een goede manier om het te bekijken.",exampleSrc:"A: There were pros and cons.\nB: On balance, it was a success.\nA: Despite the problems?\nB: On balance, we achieved more than we lost.\nA: That's a good way to look at it.",funFact:"On balance / when all is said and done. Latin/Italian loan. Financial-accounting metaphor."},
        {type:"tip",title:"📋 Wrapping Up: Summary Markers",text:"How to conclude in Dutch:\n\nSummarizing:\nkortom = in short\nal met al = all in all\nper saldo = on balance\nsamenvattend = in summary\n\nJustifying:\ntenslotte = after all (reason/justification)\n\nMoving forward:\nhoe dan ook = in any case\nhoe het ook zij = however it may be\n\nCommon mistake:\n'tenslotte' (after all) vs 'ten slotte' (finally)\nOne word = justification. Two words = enumeration."},
        {type:"mc",q:"'Tenslotte' (one word) means:",opts:["After all (justification)","Finally (in a list)","In conclusion","By the way"],ans:"After all (justification)",hint:"Tenslotte = a... all. Ten slotte = finally."},
        {type:"fb",opts:["Al","Per","Hoe","Ten"],hint:"Connector meaning: everything considered, on balance",s:"_____ met al was het een goede vakantie.",a:"Al"},
        {type:"match",pairs:[{trg:"tenslotte",src:"after all"},{trg:"al met al",src:"all in all"},{trg:"hoe dan ook",src:"in any case"},{trg:"per saldo",src:"on balance"}]},
        {type:"mc",q:"'Hoe dan ook, we moeten iets doen.' This means:",opts:["However, we shouldn't act","In any case, we need to do something","How should we do it?","We don't need to act"],ans:"In any case, we need to do something",hint:"Hoe dan ook dismisses doubt and moves forward"},
        {type:"fb",opts:["Per","Al","Hoe","Ten"],hint:"___ saldo: final weighing of pros and cons",s:"Er waren voor- en nadelen. _____ saldo was het een succes.",a:"Per"},
        {type:"mc",q:"The difference between 'tenslotte' and 'ten slotte' is:",opts:["No difference (in most cases) (in most cases)","Tenslotte is formal, ten slotte is casual (in most cases)","Tenslotte = after all, ten slotte = finally/lastly","They are different spellings of the same word"],ans:"Tenslotte = after all, ten slotte = finally/lastly",hint:"One word vs two words = different meanings"},
        {type:"fb",opts:["Hoe","Al","Per","Ten"],hint:"___ dan ook: regardless of circumstances",s:"_____ dan ook, stilzitten is geen optie.",a:"Hoe"},
        {type:"drag_fill",hint:"ALL in all a success. BECAUSE after all the team is great.",s:"Er waren problemen. {1} met al was het project een succes. {2} is het team tenslotte heel goed.",blanks:{"1":"Al","2":"Want"},pool:["Al","Want","Per","Hoe"]},
        {type:"mc",q:"'Per saldo' uses a metaphor from:",opts:["Sports equipment","Nature reserves","Cooking ingredients","Banking/finance"],ans:"Banking/finance",hint:"Saldo = balance (bank account)"},
        {type:"mc",q:"'Ten slotte' (two words) and 'tenslotte' (one word) are:",opts:["Different meanings: finally vs after all","The same word (in most cases)","Both wrong (in most cases) (in most cases)","Regional variants (in most cases)"],ans:"Different meanings: finally vs after all",hint:"Two words = lastly. One word = ___ all."},
        {type:"fb",opts:["Al","Per","Hoe","Ten"],hint:"Connector meaning: taking everything into account",s:"Er waren ups en downs. _____ met al was het een goed jaar.",a:"Al"},
        {type:"mc",q:"'Hoe dan ook' signals:",opts:["A question about how","Moving forward despite uncertainty","Complete agreement","A polite refusal"],ans:"Moving forward despite uncertainty",hint:"In any case = dismissing doubt, pressing on"}
  ]},
  {id:"v2u27l7",title:"Telefoongesprekken",icon:"📞",xp:20,board:true,steps:[
        {type:"intro",title:"Telefoongesprekken",desc:"Dutch phone etiquette has its own vocabulary and formulas. 'Met wie spreek ik?', 'mag ik u doorverbinden?', and 'kunt u dat herhalen?' are essential for professional calls.",goals:["met wie spreek ik (who am I speaking with)","mag ik u doorverbinden (may I connect you)","kunt u dat herhalen (could you repeat that)","Professional phone vocabulary"]},
        {type:"teach",trg:"met wie spreek ik?",src:"who am I speaking with?",pos:"intj",gender:null,phonetic:"met wee sprayk ik",note:"Standard phone greeting in Dutch.\nAnswer: 'U spreekt met [name]'.\nIn Dutch, you answer with your name:\n'Met De Vries' (casual) or 'U spreekt met...' (formal).",example:"A: Goedemorgen, met wie spreek ik?\nB: U spreekt met Jan de Vries.\nA: Goedemorgen meneer De Vries.\nB: Ik bel over mijn factuur.\nA: Ik verbind u door met de administratie.",exampleSrc:"A: Good morning, who am I speaking with?\nB: You are speaking with Jan de Vries.\nA: Good morning Mr De Vries.\nB: I'm calling about my invoice.\nA: I'll connect you to administration.",funFact:"Who am I speaking with? Phone-etiquette formula. Same as English structurally."},
        {type:"teach",trg:"mag ik u doorverbinden?",src:"may I connect you? / may I transfer your call?",pos:"verb",gender:null,phonetic:"makh ik uu DOOR-fur-bin-dun",note:"'Doorverbinden' = to connect/transfer (phone).\nSeparable verb: 'Ik verbind u door.'\n'Een ogenblik' = one moment (formal).\n'Een momentje' = one moment (casual).",example:"A: Ik zou graag meneer Jansen spreken.\nB: Een moment. Mag ik u doorverbinden?\nA: Ja, graag.\nB: Ik verbind u door. Een ogenblik.\nA: Dank u wel.",exampleSrc:"A: I'd like to speak to Mr Jansen.\nB: One moment. May I connect you?\nA: Yes, please.\nB: I'm transferring you. One moment.\nA: Thank you.",funFact:"'May I connect you?' Customer-service phone formula. 'Doorverbinden' (to transfer); 'door' (through) + 'verbinden' (to connect)."},
        {type:"teach",trg:"kunt u dat herhalen?",src:"could you repeat that?",pos:"intj",gender:null,phonetic:"kunt uu dat her-HAH-lun",note:"Polite request for repetition.\n'Herhalen' = to repeat.\n'Kunt u' = formal. 'Kun je' = informal.\nEssential for phone calls where you can't see the speaker.",example:"A: Uw referentienummer is B-7-4-2-9.\nB: Kunt u dat herhalen?\nA: Natuurlijk. B als in Bravo, 7-4-2-9.\nB: Dank u. En het adres?\nA: Kunt u een pen pakken?",exampleSrc:"A: Your reference number is B-7-4-2-9.\nB: Could you repeat that?\nA: Of course. B as in Bravo, 7-4-2-9.\nB: Thank you. And the address?\nA: Could you grab a pen?",funFact:"Could you repeat that? Polite formal request. Kunnen + herhalen."},
        {type:"teach",trg:"ik bel u terug",src:"I'll call you back",pos:"verb",gender:null,phonetic:"ik bel uu tuh-RUGH",note:"'Terugbellen' = to call back.\nSeparable: 'Ik bel u terug.'\n'Zij is in bespreking' = she's in a meeting.\n'Aanwezig' = present/available.",example:"A: Is mevrouw Bakker aanwezig?\nB: Zij is in bespreking. Kan zij u terugbellen?\nA: Ja graag. Ik bel anders zelf terug.\nB: Wanneer belt u terug?\nA: Over een uurtje.",exampleSrc:"A: Is Ms Bakker available?\nB: She's in a meeting. Can she call you back?\nA: Yes please. Otherwise I'll call back myself.\nB: When will you call back?\nA: In about an hour.",funFact:"'I'll call you back.' Separable verb 'terugbellen.' In main clause, 'terug' splits off to the end. 'Ik bel u terug'; literal 'I call you back.'"},
        {type:"tip",title:"📞 Dutch Phone Etiquette",text:"Dutch phone protocol:\n\n1. Answer with your name: 'Met De Vries.'\n2. Identify yourself: 'U spreekt met [name] van [company].'\n3. State purpose: 'Ik bel over/naar aanleiding van...'\n4. Transfer: 'Ik verbind u door.'\n5. Hold: 'Een ogenblik/momentje.'\n6. Unavailable: 'Zij is in bespreking.'\n7. Call back: 'Ik bel u terug.'\n\nKey cultural note:\nDutch people answer the phone with their LAST NAME.\n'Met Jansen.' (not 'Hello?')\nThis is changing with mobile phones, but still standard for business."},
        {type:"mc",q:"How do Dutch people typically answer a business phone call?",opts:["With their last name: 'Met Jansen.'","Yes?","Hello?","What do you want?"],ans:"With their last name: 'Met Jansen.'",hint:"Dutch phone etiquette: ___ first"},
        {type:"fb",opts:["spreek","bel","praat","zie"],hint:"Met wie _____ ik? Standard phone opening",s:"Met wie _____ ik? U spreekt met De Vries.",a:"spreek"},
        {type:"match",pairs:[{trg:"doorverbinden",src:"to transfer/connect"},{trg:"terugbellen",src:"to call back"},{trg:"herhalen",src:"to repeat"},{trg:"in bespreking",src:"in a meeting"}]},
        {type:"mc",q:"In 'Mag ik u _____?', which separable verb meaning 'to transfer/connect' belongs?",opts:["magverbinden","doorverbinden","uitverbinden","oververbinden"],ans:"doorverbinden",hint:"Think 'door' (through) + verbinden (connect): to put through to another line"},
        {type:"fb",opts:["terugbellen","doorverbinden","herhalen","spreken"],hint:"Terug + bellen: return a phone call",s:"Zij is niet aanwezig. Kan zij u _____?",a:"terugbellen"},
        {type:"mc",q:"'Een ogenblik' is more formal than:",opts:["Een seconde","Een minuut","Een momentje","Een uur"],ans:"Een momentje",hint:"Ogenblik = moment (formal). ___ = moment (casual)."},
        {type:"fb",opts:["herhalen","zeggen","vertellen","schrijven"],hint:"Nog een keer zeggen: say it again",s:"Kunt u dat _____? Ik heb het niet goed gehoord.",a:"herhalen"},
        {type:"drag_fill",hint:"He's IN a meeting. I'll CONNECT you.",s:"Secretaresse: 'Meneer Bakker is {1} bespreking. Ik {2} u door met zijn collega.'",blanks:{"1":"in","2":"verbind"},pool:["in","verbind","met","bel"]},
        {type:"mc",q:"'Ik bel naar aanleiding van uw advertentie.' This means:",opts:["I'm calling to complain loudly about your ad","I'm calling about an urgent emergency","I'm calling to cancel your recent ad (in most cases)","I'm calling in response to your advertisement"],ans:"I'm calling in response to your advertisement",hint:"Naar aanleiding van = in r... to / regarding"},
        {type:"mc",q:"When answering a business phone in Dutch, you say:",opts:["Your last name: 'Met Jansen'","What do you want from me?","Hello, how can I help you?","Nothing, just wait in silence"],ans:"Your last name: 'Met Jansen'",hint:"Dutch phone etiquette: ___ first"},
        {type:"fb",opts:["verbind","bel","spreek","stuur"],hint:"Door + a verb meaning 'to connect': transfer to another line",s:"Zij is niet aanwezig. Ik _____ u door met haar collega.",a:"verbind"},
        {type:"mc",q:"'Kunt u dat herhalen?' is used on the phone when you:",opts:["Want to end the call quickly","Did not understand what was said","Want to complain about service","Need to transfer the call"],ans:"Did not understand what was said",hint:"A verb meaning 'to repeat': asking for clarification"}
  ]},
  {id:"v2u27l8",title:"Vrij Gesprek",icon:"🏆",xp:35,board:true,steps:[
        {type:"intro",title:"Vrij Gesprek",desc:"Comprehensive review of Unit 27: hedging, discourse markers, opinions, agreement/disagreement, conversation management, and phone etiquette. Every question combines multiple discourse skills.",goals:["Review all discourse markers and hedging","Apply conversation management phrases","Combine opinion expressions with agreement/disagreement","Master professional phone language"]},
        {type:"mc",q:"'Wellicht moeten we het plan aanpassen.' 'Wellicht' means:",opts:["Perhaps","Certainly","Never","Always"],ans:"Perhaps",hint:"More formal than 'misschien'"},
        {type:"fb",opts:["Om eerlijk","Wat mij","Naar mijn","Al met"],hint:"Om ___ te zijn: a phrase for giving a frank assessment",s:"_____ te zijn, de presentatie was niet zo sterk.",a:"Om eerlijk"},
        {type:"mc",q:"'Eventueel' in Dutch means 'possibly', NOT:",opts:["Maybe","Eventually","If needed","Optionally"],ans:"Eventually",hint:"False friend: 'eventueel' means possibly, not this English word"},
        {type:"fb",opts:["punt","vraag","probleem","antwoord"],hint:"Je hebt daar een _____: acknowledging validity",s:"Daar heb je een _____. Het onderwijs verdient meer aandacht.",a:"punt"},
        {type:"match",pairs:[{trg:"overigens",src:"by the way (formal)"},{trg:"eigenlijk",src:"actually"},{trg:"inderdaad",src:"indeed"},{trg:"maar goed",src:"anyway"},{trg:"ik bel u terug",src:"I'll call you back"}]},
        {type:"mc",q:"'Ik ben van mening dat' is appropriate in:",opts:["A text to a friend","A shopping list","A formal essay or debate","A birthday card"],ans:"A formal essay or debate",hint:"Very ___ opinion expression"},
        {type:"fb",opts:["Naar","Van","Met","In"],hint:"Formal opinion phrase: ___ mijn mening",s:"_____ mijn mening is meer investering in onderwijs nodig.",a:"Naar"},
        {type:"mc",q:"'Al met al was het een goede dag.' This means:",opts:["Not at all it was good","After all the problems","At the end of the day","All in all it was a good day"],ans:"All in all it was a good day",hint:"Al met al = taking everything together"},
        {type:"fb",opts:["betwijfel","geloof","weet","denk"],hint:"Expressing skepticism: ik _____ of...",s:"Ik _____ of dat realistisch is.",a:"betwijfel"},
        {type:"drag_fill",hint:"WHO am I speaking with? You're speaking WITH De Vries.",s:"Am Telefon: 'Met {1} spreek ik?' Antwoord: 'U spreekt {2} De Vries.'",blanks:{"1":"wie","2":"met"},pool:["wie","met","wat","van"]},
        {type:"mc",q:"'Kortom' at the start of a conclusion means:",opts:["In short / in brief","However","For example","On the other hand"],ans:"In short / in brief",hint:"A concise summary connector that wraps up an argument"},
        {type:"fb",opts:["Hoe","Al","Per","Ten"],hint:"___ dan ook: regardless of everything",s:"_____ dan ook, we moeten een besluit nemen.",a:"Hoe"},
        {type:"match",pairs:[{trg:"naar mijn mening",src:"in my opinion"},{trg:"wat mij betreft",src:"as far as I'm concerned"},{trg:"dat klopt deels",src:"that's partly true"},{trg:"om eerlijk te zijn",src:"to be honest"}]},
        {type:"mc",q:"'Mag ik u doorverbinden met mijn collega?' You would hear this:",opts:["In a restaurant","On the phone","At a party","In a classroom"],ans:"On the phone",hint:"Doorverbinden = to transfer a ___ call"},
        {type:"fb",opts:["zeggen","doen","schrijven","lezen"],hint:"Laat ik het zo _____: rephrasing diplomatically",s:"Laat ik het zo _____: er is ruimte voor verbetering.",a:"zeggen"},
        {type:"mc",q:"Which hedging word is a FALSE FRIEND with English?",opts:["misschien","wellicht","eventueel","mogelijkerwijs"],ans:"eventueel",hint:"This Dutch false friend actually means 'possibly' in English"},
        {type:"fb",opts:["Per","Al","Ten","Om"],hint:"___ saldo: final weighing up of everything",s:"_____ saldo was het project een succes.",a:"Per"},
        {type:"mc",q:"To politely disagree in Dutch, you could say:",opts:["Dat is onzin!","Je hebt ongelijk.","Nee!","Ik betwijfel of dat klopt."],ans:"Ik betwijfel of dat klopt.",hint:"Polite doubt is more appropriate than blunt contradiction"}
  ]},
  {id:"v2uNl_sign",title:"Wat Belangrijk Is Voor Mij",icon:"💭",xp:15,board:true,steps:[
    {type:"intro",title:"Writing About Personal Significance",desc:"Learn to write about meaningful experiences, memories, and values in Dutch. Essential for NT2 B2 autobiographical writing.",goals:["Express what matters to you","Reflect on formative memories","Describe your personal values"]},
    {type:"teach",trg:"betekenen",src:"to mean / to signify",pos:"verb",gender:null,note:"'Betekenen' expresses significance or meaning.\n'Dat betekent veel voor mij.' = That means a lot to me.\nNoun: 'de betekenis' (the meaning) = de-word.",example:"A: Wat betekent die foto voor jou?\nB: Die foto betekent veel voor mij.\nA: Waarom is hij zo bijzonder?\nB: Het is de laatste foto van mijn familie.",exampleSrc:"A: What does that photo mean to you?\nB: That photo means a lot to me.\nA: Why is it so special?\nB: It's the last photo of my family.",funFact:"Related to 'teken' (sign/symbol). To betekenen is literally to 'be-sign' something, giving it symbolic weight."},
    {type:"teach",trg:"de herinnering",src:"the memory (a specific recollection)",pos:"noun",gender:"c",note:"De herinnering (de-word). Plural: de herinneringen.\n'Aan iets terugdenken' = to think back on something.\nDistinct from 'het geheugen' (memory as a faculty).",example:"A: Welke herinnering is de mooiste?\nB: De herinnering aan mijn eerste dag op school.\nA: Dat klinkt bijzonder.\nB: Ja, het leven was groot voor mij als kind.",exampleSrc:"A: Which memory is the most beautiful?\nB: The memory of my first day at school.\nA: That sounds special.\nB: Yes, life felt big to me as a child.",funFact:"From 'herinneren' (to remind/recall). The 'her-' prefix in Dutch often signals repetition or return, as in 'herhalen' (to repeat) and 'herstellen' (to recover)."},
    {type:"teach",trg:"de emotie",src:"the emotion",pos:"noun",gender:"c",note:"De emotie (de-word). Plural: de emoties.\n'Emotioneel' = emotional (adjective).\n'Emoties tonen' = to show emotions.\nDutch culture: showing emoties is acceptable but moderation valued.",example:"A: Schrijven over emoties is moeilijk.\nB: Ja, maar het is goed voor het leven.\nA: Welke emotie vind jij het sterkst?\nB: De emotie die ik voel bij de ervaring van muziek.",exampleSrc:"A: Writing about emotions is difficult.\nB: Yes, but it is good for life.\nA: Which emotion do you find the strongest?\nB: The emotion I feel with the experience of music.",funFact:"Directly borrowed from French 'emotion', which came from Latin 'emovere' (to move out, to stir up). Emotions literally 'move' you."},
    {type:"teach",trg:"ontroeren",src:"to move emotionally / to touch (emotionally)",pos:"verb",gender:null,note:"A strong emotional response. Not separable.\n'Ik ben ontroerd.' = I am moved/touched.\nPast tense: 'Het ontroerde mij.' = It moved me.\nMore intense than 'raken' (to affect/touch).",example:"A: Wat ontroerde jou het meest?\nB: De toespraak van mijn vader ontroerde mij.\nA: Dat is goed om te weten.\nB: Zo'n ervaring vergeet je nooit.",exampleSrc:"A: What moved you the most?\nB: My father's speech moved me.\nA: That is good to know.\nB: You never forget such an experience.",funFact:"From 'roeren' (to stir). The 'ont-' prefix often intensifies or triggers in Dutch, as in 'ontdekken' (to discover) and 'ontwikkelen' (to develop)."},
    {type:"teach",trg:"onvergetelijk",src:"unforgettable",pos:"adj",gender:null,note:"'On-' = un- (negation) + 'vergeten' (to forget) + '-lijk' (adjective suffix).\n'Een onvergetelijke dag.' = An unforgettable day.\nAlways inflected: onvergetelijke (with noun).",example:"A: Was het een onvergetelijke ervaring?\nB: Ja, onvergetelijk voor de hele familie.\nA: Dat denk ik ook.\nB: Zo'n dag betekent veel.",exampleSrc:"A: Was it an unforgettable experience?\nB: Yes, unforgettable for the whole family.\nA: I think so too.\nB: A day like that means a lot.",funFact:"Built from three pieces: 'on' (un-) + 'vergeet' (forget, from vergeten) + 'lijk' (-able). Dutch is excellent at building long, precise words from small parts."},
    {type:"teach",trg:"de waarde",src:"the value (abstract)",pos:"noun",gender:"c",note:"De waarde (de-word). Plural: de waarden.\n'Kernwaarden' = core values.\nDistinct from 'de prijs' (price/monetary value).\n'Persoonlijke waarden' = personal values.",example:"A: Welke waarden zijn voor jou het belangrijkst?\nB: Eerlijkheid en vriendschap betekenen veel voor mij.\nA: Dat vind ik goed om te weten.\nB: Die waarden heb ik van mijn familie geleerd.",exampleSrc:"A: Which values are most important to you?\nB: Honesty and friendship mean a lot to me.\nA: That is good to know.\nB: I learned those values from my family.",funFact:"From Old Dutch 'werdh' (worth). Related to English 'worth' and German 'Wert'. The same root gives Dutch 'waarderen' (to appreciate) and 'waardevol' (valuable)."},
    {type:"teach",trg:"vormgeven",src:"to shape / to give form to",pos:"verb",gender:null,note:"Separable verb: vorm + geven.\n'Ik geef vorm aan...' = I give shape to...\n'De ervaring gaf vorm aan mijn leven.' = The experience shaped my life.\nInfinitive: 'vormgeven'. Past: 'gaf vorm'.",example:"A: Hoe gaf die ervaring vorm aan jou?\nB: Het gaf vorm aan mijn waarden.\nA: Dat is bijzonder om te weten.\nB: Ja, het leven heeft mij veel geleerd.",exampleSrc:"A: How did that experience shape you?\nB: It shaped my values.\nA: That is special to know.\nB: Yes, life has taught me a lot.",funFact:"A compound of 'vorm' (form/shape) + 'geven' (to give). Separable verbs are a hallmark of Dutch and German, splitting in main clauses but staying together in infinitives."},
    {type:"tip",title:"Persoonlijk Schrijven in het Nederlands",text:"The B2 NT2 writing task often asks you to reflect personally. Key sentence starters:\n\nDat betekent veel voor mij omdat... (That means a lot to me because...)\nDe herinnering aan... is onvergetelijk. (The memory of... is unforgettable.)\nDeze ervaring gaf vorm aan... (This experience shaped...)\nWat mij het meest ontroert, is... (What moves me the most is...)\n\nStructure tip: open with a specific memory, explain why it matters, link it to a personal value.",deepDive:"Authentic personal writing in Dutch uses concrete examples before abstract statements. Start with a specific scene ('Op mijn zevende jaar...'), then name the emotion it produced, then state what value or insight it gave you. This mirrors the NT2 B2 scoring rubric for 'textuele samenhang' (textual coherence)."},
    {type:"mc",q:"'Die dag betekende veel voor mij.' What does 'betekende' express?",opts:["The day had personal significance","The day was difficult","The day ended well","The day was long"],ans:"The day had personal significance",hint:"Betekenen = to signify or mean something personally"},
    {type:"fb",s:"De _____ aan mijn schooltijd is onvergetelijk.",a:"herinnering",opts:["herinnering","emotie","waarde","ervaring"],hint:"A specific personal recollection stored in the mind"},
    {type:"mc",q:"Which sentence uses 'ontroeren' correctly?",opts:["De film herinnerde groot.","De film ontroerde mij diep.","De film betekende mij.","De film vormgaf mij."],ans:"De film ontroerde mij diep.",hint:"Which verb describes being emotionally stirred or touched? Pick the option with that verb."},
    {type:"fb",s:"Een _____ dag vergeet je nooit.",a:"onvergetelijke",opts:["onvergetelijke","grote","vroege","bijzondere"],hint:"The adjective form of 'unforgettable' before a de-word noun"},
    {type:"mc",q:"'Eerlijkheid is een belangrijke waarde.' Here 'waarde' means:",opts:["a specific emotion","a monetary price","a personal principle / value","an unforgettable memory"],ans:"a personal principle / value",hint:"De waarde in the abstract sense refers to a deeply held …"},
    {type:"fb",s:"Die ervaring gaf _____ aan mijn persoonlijkheid.",a:"vorm",opts:["vorm","tijd","waarde","emotie"],hint:"Vormgeven is separable: geef + ___ aan (give shape to)"},
    {type:"mc",q:"'Welke emotie voel jij het sterkst?' This question asks about:",opts:["your most important value","an unforgettable experience","your favourite memory","the emotion you feel most intensely"],ans:"the emotion you feel most intensely",hint:"De emotie = a feeling. 'Het sterkst' = most strongly."},
    {type:"match",pairs:[{trg:"betekenen",src:"to mean / signify"},{trg:"de herinnering",src:"the memory (a recollection)"},{trg:"ontroeren",src:"to move emotionally"},{trg:"onvergetelijk",src:"unforgettable"}]},
    {type:"match",pairs:[{trg:"de emotie",src:"the emotion"},{trg:"de waarde",src:"the value (abstract)"},{trg:"vormgeven",src:"to shape / give form to"}]}
  ]},
  {id:"nlv2_u27l_b2_civic",title:"Maatschappij & Wetgeving",icon:"⚖️",xp:20,board:true,steps:[
    {type:"intro",title:"Maatschappij & Wetgeving",desc:"Six core civic discourse words for NT2 B2: talking about society, governance, and social justice. Essential vocabulary for opinion essays, debates, and formal discussions.",goals:["het nadeel (the disadvantage)","de sociale rechtvaardigheid (social justice)","de gelijkheid (equality)","de regering (the government)","het probleem (the problem)","de wetgeving (legislation)"]},
    {type:"teach",trg:"het nadeel",src:"the disadvantage",pos:"noun",gender:"n",phonetic:"hut NAH-dayl",note:"Het-word. Plural: nadelen.\nOpposite: het voordeel (the advantage).\n'Het nadeel is dat...' = The disadvantage is that...\nCommon in essays and debates.",example:"A: Wat is het nadeel van dit plan?\nB: Het kost veel geld en het duurt lang.\nA: Zijn er ook voordelen?\nB: Ja, maar het nadeel is groter dan het voordeel.",exampleSrc:"A: What is the disadvantage of this plan?\nB: It costs a lot of money and takes a long time.\nA: Are there also advantages?\nB: Yes, but the disadvantage is greater than the advantage.",funFact:"Compound of 'na' (behind/after) and 'deel' (part). Literally the part that lags behind, contrasting with 'voordeel' (advantage) where 'voor' means ahead. A neat pair that shows how Dutch builds opposites by swapping prefixes."},
    {type:"teach",trg:"de sociale rechtvaardigheid",src:"social justice",pos:"noun",gender:"c",phonetic:"duh soh-SJAH-luh REKHT-yar-dikh-hayd",note:"De-word (common gender). Compound noun.\n'Rechtvaardig' = just/fair.\n'Rechtvaardigheid' = justice/fairness.\nCore concept in Dutch civic and political discourse.",example:"A: Waarom is sociale rechtvaardigheid belangrijk?\nB: Zonder sociale rechtvaardigheid groeit de ongelijkheid.\nA: Hoe bereiken we meer gelijkheid?\nB: De regering moet beleid maken dat iedereen beschermt.",exampleSrc:"A: Why is social justice important?\nB: Without social justice, inequality grows.\nA: How do we achieve more equality?\nB: The government must make policy that protects everyone.",funFact:"The term entered Dutch political language in the 20th century, shaped by the labour movement and Christian social thought ('christelijk-sociale beweging'). Both traditions shaped the Dutch welfare state, one of the world's most comprehensive."},
    {type:"teach",trg:"de gelijkheid",src:"equality",pos:"noun",gender:"c",phonetic:"duh khuh-LAYK-hayt",note:"De-word. From 'gelijk' (equal) + '-heid' (abstract noun suffix).\n'Gelijkheid voor de wet' = equality before the law.\nContrast: ongelijkheid (inequality, unit 26).\nCore value in the Dutch constitution.",example:"A: De gelijkheid van alle burgers staat in de wet.\nB: Ja, maar in de praktijk is er nog werk te doen.\nA: De sociale rechtvaardigheid vraagt om meer gelijkheid.\nB: Daar heeft de regering een grote rol in.",exampleSrc:"A: The equality of all citizens is written in the law.\nB: Yes, but in practice there is still work to be done.\nA: Social justice demands more equality.\nB: The government plays a big role in that.",funFact:"Article 1 of the Dutch constitution (Grondwet, 1983) is the equality clause: 'Allen die zich in Nederland bevinden, worden in gelijke gevallen gelijk behandeld.' It is the first and most fundamental right in Dutch law."},
    {type:"teach",trg:"de regering",src:"the government (executive)",pos:"noun",gender:"c",phonetic:"duh ruh-KHE-ring",note:"De-word. Refers specifically to the executive branch.\n'De Tweede Kamer' = the parliament (legislature).\n'Het kabinet' = the cabinet.\n'De regeringspartij' = governing party.\nDistinct from 'de overheid' (public authority in general).",example:"A: Wat doet de regering aan het probleem?\nB: De regering heeft nieuwe plannen gemaakt.\nA: Is dat genoeg?\nB: Het nadeel is dat het lang duurt voordat alles verandert.",exampleSrc:"A: What is the government doing about the problem?\nB: The government has made new plans.\nA: Is that enough?\nB: The disadvantage is that it takes a long time before everything changes.",funFact:"The Netherlands has had coalition governments ('coalitiekabinetten') for over a century. Because no single party wins a majority, multiple parties must agree on a 'regeerakkoord' (coalition agreement). This consensus culture is called the 'poldermodel'."},
    {type:"teach",trg:"het probleem",src:"the problem",pos:"noun",gender:"n",phonetic:"hut proh-BLAYM",note:"Het-word. Plural: problemen.\n'Een probleem oplossen' = to solve a problem.\n'Het is een groot probleem.' = It is a big problem.\nCore word in civic discourse and essays.",example:"A: Wat is het grootste probleem in de samenleving?\nB: Volgens mij is ongelijkheid het grootste probleem.\nA: Hoe lossen we dat probleem op?\nB: Door beleid te maken dat gericht is op sociale rechtvaardigheid.",exampleSrc:"A: What is the biggest problem in society?\nB: In my opinion, inequality is the biggest problem.\nA: How do we solve that problem?\nB: By making policy aimed at social justice.",funFact:"Borrowed from French 'probleme', which came from Greek 'problema' (obstacle put forward, challenge). The Greek root 'pro-ballein' means 'to throw forward', as if a problem is an obstacle thrown in your path."},
    {type:"teach",trg:"de wetgeving",src:"legislation / the law (body of laws)",pos:"noun",gender:"c",phonetic:"duh WET-khay-ving",note:"De-word. From 'wet' (law) + 'geven' (to give) + '-ing' (noun suffix).\n'Wetgeving maken' = to make legislation.\n'De nieuwe wetgeving' = the new legislation.\nDistinct from 'de wet' (a single specific law).",example:"A: De regering heeft nieuwe wetgeving ingevoerd.\nB: Wat regelt die wetgeving?\nA: Het gaat over gelijkheid op de arbeidsmarkt.\nB: Dat is een stap in de goede richting.",exampleSrc:"A: The government has introduced new legislation.\nB: What does that legislation regulate?\nA: It is about equality in the labour market.\nB: That is a step in the right direction.",funFact:"The Dutch legislative process is bicameral: a bill passes through the Tweede Kamer (House of Representatives, directly elected) and the Eerste Kamer (Senate, elected by provincial councils). Both chambers must approve a bill before it becomes 'wetgeving'."},
    {type:"tip",title:"Civic Discourse: Abstract Nouns with -heid",text:"Dutch builds many abstract civic nouns with the suffix -heid:\n\ngelijk (equal) → gelijkheid (equality)\nonrechtvaardig (unjust) → onrechtvaardigheid (injustice)\nrechtvaardig (just) → rechtvaardigheid (justice)\nvrij (free) → vrijheid (freedom)\nveilig (safe) → veiligheid (safety)\n\nAll -heid nouns are de-words.\nThis pattern lets you build civic vocabulary systematically.\n\nNote on articles:\nhet nadeel, het probleem (het-words)\nde gelijkheid, de regering, de wetgeving, de sociale rechtvaardigheid (de-words)"},
    {type:"mc",q:"'Het nadeel van dit plan is de hoge prijs.' What does 'nadeel' mean?",opts:["the disadvantage","the price","the problem","the advantage"],ans:"the disadvantage",hint:"Think of 'na' (behind) and 'deel' (part). The part that falls behind."},
    {type:"fb",s:"De _____ heeft nieuwe plannen voor de economie gemaakt.",a:"regering",opts:["regering","wetgeving","gelijkheid","situatie"],hint:"The executive branch of government"},
    {type:"mc",q:"'De gelijkheid van alle burgers staat in de Grondwet.' What right does this refer to?",opts:["The right to vote","Equality before the law","Freedom of speech","The right to housing"],ans:"Equality before the law",hint:"Gelijkheid = equal treatment. The Grondwet is the Dutch constitution."},
    {type:"fb",s:"De _____ regelt de rechten en plichten van burgers.",a:"wetgeving",opts:["wetgeving","gelijkheid","situatie","politiek"],hint:"The body of laws made by the legislature"},
    {type:"match",pairs:[{trg:"het nadeel",src:"the disadvantage"},{trg:"de gelijkheid",src:"equality"},{trg:"de regering",src:"the government (executive)"},{trg:"het probleem",src:"the problem"}]},
    {type:"mc",q:"'De sociale rechtvaardigheid' is a compound noun. Which article does it take?",opts:["geen artikel","het","de","een"],ans:"de",hint:"All -heid nouns are de-words. Rechtvaardigheid ends in -heid."},
    {type:"fb",s:"Ongelijkheid is een groot _____  in de samenleving.",a:"probleem",opts:["probleem","nadeel","wetgeving","gelijkheid"],hint:"The general word for an issue or difficulty (het-word)"},
    {type:"mc",q:"What is the relationship between 'het voordeel' and 'het nadeel'?",opts:["They are unrelated","They are compound verbs","They are synonyms","They are antonyms"],ans:"They are antonyms",hint:"Voor (ahead) vs. na (behind): advantage vs. disadvantage"},
    {type:"fb",s:"De _____ bevordert gelijkheid en sociale rechtvaardigheid.",a:"wetgeving",opts:["wetgeving","oorzaak","situatie","economie"],hint:"The body of laws that regulates society"},
    {type:"match",pairs:[{trg:"de wetgeving",src:"legislation"},{trg:"de sociale rechtvaardigheid",src:"social justice"},{trg:"de gelijkheid",src:"equality"},{trg:"het nadeel",src:"the disadvantage"}]},
    {type:"mc",q:"A classmate says: 'De regering en de wetgeving zijn hetzelfde.' Is this correct?",opts:["No: de regering = executive, de wetgeving = laws","No: de regering makes laws, de wetgeving is the parliament","Yes, in Dutch they are synonyms","Yes, they are the same"],ans:"No: de regering = executive, de wetgeving = laws",hint:"One is the cabinet that governs the country. The other is the set of rules parliament passes. These are distinct branches."},
    {type:"fb",s:"Zonder sociale rechtvaardigheid neemt de _____ in de samenleving toe.",a:"ongelijkheid",opts:["ongelijkheid","gelijkheid","wetgeving","situatie"],hint:"The antonym of gelijkheid: un- + equal + -heid"},
    {type:"mc",q:"Which word means 'the executive branch of government' in Dutch?",opts:["het parlement","de regering","de burger","de wetgeving"],ans:"de regering",hint:"The entity that governs and implements policy. Not the legislature."}
  ]}
]};
